import random

random.seed(42)

# Create a pixelated diamond/rhombus shape
# Build from a grid of cells where each cell may or may not be filled
cell_size = 1.0
thickness = 1.0

# Define a pixelated diamond shape using a grid
# Use a diamond pattern with random edge perturbations
grid_w = 24
grid_h = 14

cells = set()

# Create base diamond shape
cx, cy = grid_w / 2, grid_h / 2
for x in range(grid_w):
    for y in range(grid_h):
        # Diamond equation with some thickness
        dx = abs(x - cx) / (grid_w / 2)
        dy = abs(y - cy) / (grid_h / 2)
        if dx + dy <= 1.0:
            cells.add((x, y))

# Add random perturbations on the edges
