for (x, y) in list(cells):
    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        nx, ny = x + dx, y + dy
        if (nx, ny) not in cells and 0 <= nx < grid_w and 0 <= ny < grid_h:
            edge_cells.append((nx, ny))

# Randomly add some edge cells
